import{_ as r,o as a,c as s,a0 as n}from"./chunks/framework.DV6pVIgV.js";const h=JSON.parse('{"title":"容器：ECS、EKS、Fargate 與 ECR","description":"","frontmatter":{},"headers":[],"relativePath":"clf-c02/5.md","filePath":"clf-c02/5.md","lastUpdated":1783610848000}'),e={name:"clf-c02/5.md"};function o(l,t,d,g,i,p){return a(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="容器-ecs、eks、fargate-與-ecr" tabindex="-1">容器：ECS、EKS、Fargate 與 ECR <a class="header-anchor" href="#容器-ecs、eks、fargate-與-ecr" aria-label="Permalink to &quot;容器：ECS、EKS、Fargate 與 ECR&quot;">​</a></h1><p>容器(container)是這章的主角。你會學到：容器好在哪（以及它和 EC2 的差別）、怎麼把程式打包成映像檔、選對編排器、決定底層主機由誰管，最後把這些拼成一個「從打包到上線」的完整流程。</p><h2 id="先備知識" tabindex="-1">先備知識 <a class="header-anchor" href="#先備知識" aria-label="Permalink to &quot;先備知識&quot;">​</a></h2><ul><li><p><strong>容器 vs 虛擬機</strong></p><ul><li><a href="https://aws.amazon.com/compare/the-difference-between-containers-and-virtual-machines/" target="_blank" rel="noreferrer">AWS：Containers vs. VMs</a></li></ul></li><li><p><strong>Docker</strong></p><ul><li><a href="https://chengweihu.com/docker-tutorial/" target="_blank" rel="noreferrer">Docker 基礎教學與介紹 101</a></li></ul></li><li><p><strong>Kubernetes</strong></p><ul><li><a href="https://aws.amazon.com/kubernetes/" target="_blank" rel="noreferrer">AWS：Kubernetes on AWS</a></li><li><a href="https://aws.amazon.com/compare/the-difference-between-kubernetes-and-docker/" target="_blank" rel="noreferrer">AWS：Kubernetes vs. Docker</a></li></ul></li></ul><hr><h2 id="為什麼要用容器-先看它和虛擬機的差別" tabindex="-1">為什麼要用容器：先看它和虛擬機的差別 <a class="header-anchor" href="#為什麼要用容器-先看它和虛擬機的差別" aria-label="Permalink to &quot;為什麼要用容器：先看它和虛擬機的差別&quot;">​</a></h2><p>要理解容器，最快的方式是拿它跟上一章學的 <strong>EC2（虛擬機）</strong> 比。</p><p>一台虛擬機（VM）是「一整台電腦的數位複本」——它有自己完整的作業系統，跑在實體主機的作業系統之上。所以每開一台 VM，都要扛一份完整 OS 的重量：開機慢、佔空間、資源要事先備好。</p><p><strong>容器</strong>則只打包「你的程式 + 它需要的相依套件」，然後<strong>共用底層主機的作業系統核心</strong>。因為不必每次都搬一整套 OS，容器<strong>輕量、啟動快、好搬移</strong>。</p><blockquote><p>用貨櫃來想「容器（container）」這個名字：貨櫃把貨物用一個標準化的箱子裝好，不管換到哪艘船、哪台卡車都能直接搬、不必重新打包。容器對軟體做的是同一件事——把程式連同環境裝進一個標準單位，<strong>在你的筆電、在測試機、在雲上跑起來都一模一樣</strong>，解決「明明我電腦上可以跑」的問題。</p></blockquote><table tabindex="0"><thead><tr><th></th><th>虛擬機（如 EC2）</th><th>容器</th></tr></thead><tbody><tr><td>打包什麼</td><td>一整套作業系統 + 應用</td><td>只有應用 + 相依套件</td></tr><tr><td>作業系統</td><td>每台各有一份完整 OS</td><td>共用主機的 OS 核心</td></tr><tr><td>啟動速度</td><td>較慢（要開機）</td><td>極快</td></tr><tr><td>資源佔用</td><td>較重</td><td>輕量</td></tr><tr><td>隔離強度</td><td>強（完整隔離）</td><td>相對輕（行程層級隔離）†</td></tr></tbody></table><blockquote><p>† <strong>Fargate 是例外</strong>：每個 task 跑在自己的 Firecracker micro-VM 裡，隔離強度接近 VM 級，而非行程層級。</p></blockquote><blockquote><p>容器和虛擬機<strong>不是二選一</strong>。最常見的是「容器跑在虛擬機裡」——一台 EC2 上面跑很多容器。</p></blockquote><h2 id="映像檔與容器" tabindex="-1">映像檔與容器 <a class="header-anchor" href="#映像檔與容器" aria-label="Permalink to &quot;映像檔與容器&quot;">​</a></h2><ul><li><strong>映像檔（Image）</strong> 是「範本」——一個唯讀的打包成品，裡面是程式加上它要的環境。可以想成「餅乾模具」。</li><li><strong>容器（Container）</strong> 是「用範本跑起來的實體」——由映像檔啟動的執行中程式。可以想成「用模具壓出來的餅乾」，一個模具可以壓出很多片。</li></ul><p>流程是：<strong>先做出映像檔 → 存到倉庫 → 需要時從映像檔啟動一或多個容器</strong>。那個「倉庫」在 AWS 上就是稍後會講的 <strong>ECR</strong>。</p><h2 id="編排-orchestration" tabindex="-1">編排（Orchestration） <a class="header-anchor" href="#編排-orchestration" aria-label="Permalink to &quot;編排（Orchestration）&quot;">​</a></h2><p>一兩個容器你還能手動顧。但當你有幾十、幾百個容器時，一堆問題冒出來：哪個容器該跑在哪台機器？某個掛了要不要自動重啟？流量變大要不要多開幾個、變小要不要收掉？多台機器之間怎麼分配？</p><p><strong>替你自動處理這些事的系統，就叫編排器（Orchestrator）。</strong> 它是容器世界的「調度中心」。在 AWS 上跑容器，核心就是兩個要分開決定的問題。</p><h3 id="決定一-用哪個編排器" tabindex="-1">決定一：用哪個編排器 <a class="header-anchor" href="#決定一-用哪個編排器" aria-label="Permalink to &quot;決定一：用哪個編排器&quot;">​</a></h3><table tabindex="0"><thead><tr><th>編排器</th><th>是什麼</th><th>選它的理由</th></tr></thead><tbody><tr><td><strong>ECS（Elastic Container Service）</strong></td><td>AWS 原生的容器編排服務</td><td>較簡單、與 AWS 服務整合最好、控制平面免費</td></tr><tr><td><strong>EKS（Elastic Kubernetes Service）</strong></td><td>AWS 託管的 Kubernetes</td><td>開源業界標準、可跨雲 / 地端移植、團隊已熟 K8s</td></tr></tbody></table><p><strong>ECS</strong> 是 AWS 自己設計的編排器。它的控制平面（決定容器怎麼調度的大腦）完全由 AWS 管，你不必碰，所以上手最快、和 IAM、ALB、CloudWatch 等 AWS 服務接得最順。代價是它是 AWS 專屬的，綁在 AWS 生態裡。</p><p><strong>EKS</strong> 則是把 <strong>Kubernetes</strong>（業界最主流的開源容器編排標準，常簡寫 K8s）交給 AWS 託管。選它的最大理由是<strong>可攜性與標準化</strong>：同一套 Kubernetes 設定，可以在 AWS、其他雲、甚至自家機房用同樣的工具跑。代價是 Kubernetes 本身較複雜，要懂它的一套術語與運作。</p><blockquote><p><strong>ECS vs EKS</strong>：要 AWS 原生、簡單、整合好 → <strong>ECS</strong>；要開源 Kubernetes、跨雲可攜、團隊已用 K8s → <strong>EKS</strong>。</p></blockquote><h3 id="決定二-容器實際跑在哪" tabindex="-1">決定二：容器實際跑在哪 <a class="header-anchor" href="#決定二-容器實際跑在哪" aria-label="Permalink to &quot;決定二：容器實際跑在哪&quot;">​</a></h3><table tabindex="0"><thead><tr><th>計算選項</th><th>誰管主機</th><th>你要負責什麼</th></tr></thead><tbody><tr><td><strong>EC2 啟動類型</strong></td><td>你自己</td><td>準備 EC2、修補更新、規劃容量與擴展</td></tr><tr><td><strong>Fargate</strong></td><td>AWS（無伺服器）</td><td>只管容器本身，主機完全不用碰</td></tr></tbody></table><ul><li><strong>EC2 啟動類型</strong>：容器跑在你自己管理的一群 EC2 上。你握有最多掌控權（可挑機型、可裝特殊東西、用量穩定時可能更省），但也要自己負責這些主機的修補、容量與擴展。</li><li><strong>Fargate</strong>：無伺服器模式。你只要說「我要跑這個容器、給它多少 CPU / 記憶體」，AWS 就替你在背後準備好主機來跑，<strong>你完全不用管任何伺服器</strong>，按容器實際用到的資源計費。</li></ul><blockquote><p>📌 <strong>要不要管主機</strong>：完全不想管、想最省事 → <strong>Fargate</strong>；要自管 EC2 主機、要最多掌控 → <strong>EC2 啟動類型</strong>。</p></blockquote><h2 id="ecr-存放映像檔的私有倉庫" tabindex="-1">ECR：存放映像檔的私有倉庫 <a class="header-anchor" href="#ecr-存放映像檔的私有倉庫" aria-label="Permalink to &quot;ECR：存放映像檔的私有倉庫&quot;">​</a></h2><p><strong>ECR（Elastic Container Registry）</strong> 是 AWS 託管的私有映像檔倉庫。你把打包好的映像檔推（push）上去，ECS 或 EKS 要跑容器時就從這裡拉（pull）下來。它會<strong>保存與版本管理</strong>你的映像檔，和 IAM 權限整合，還能對映像檔做<strong>弱點掃描</strong>，檢查裡面的套件有沒有已知漏洞。</p><blockquote><p>📌 <strong>ECR 是「放映像檔的地方」，ECS / EKS 是「用映像檔跑容器的地方」。</strong></p></blockquote><h2 id="完整架構" tabindex="-1">完整架構 <a class="header-anchor" href="#完整架構" aria-label="Permalink to &quot;完整架構&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        ┌─ 編排器：ECS（AWS 原生） 或 EKS（Kubernetes）  ← 決定一</span></span>
<span class="line"><span>容器 ───┤</span></span>
<span class="line"><span>        ├─ 跑在哪：EC2 啟動類型（自管主機） 或 Fargate（免管主機）  ← 決定二</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        └─ 映像檔倉庫：ECR（ECS / EKS 從這裡拉映像）</span></span></code></pre></div><p>把上面所有零件串成一條「從打包到上線」的路，這章就通了：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 打包    你的網站程式 → 做成 Docker 映像檔</span></span>
<span class="line"><span>2. 上傳    把映像檔 push 到 ECR（私有倉庫）</span></span>
<span class="line"><span>3. 定義    告訴 ECS：要跑哪個映像檔、給多少 CPU / 記憶體</span></span>
<span class="line"><span>4. 執行    ECS 在 Fargate 上啟動容器（主機 AWS 管，你不用碰）</span></span>
<span class="line"><span>5. 分流    前面掛一個 ALB，把使用者流量平均分到多個容器</span></span>
<span class="line"><span>6. 伸縮    流量大自動多開容器、流量小自動收掉</span></span></code></pre></div><p><strong>ECR</strong> 存映像檔、<strong>ECS</strong> 當調度中心、<strong>Fargate</strong> 出主機、<strong>ALB</strong>分流——一個容器化應用，就是這幾個服務各司其職。</p><h2 id="容器-vs-lambda-vs-ec2-什麼時候選容器" tabindex="-1">容器 vs Lambda vs EC2：什麼時候選容器 <a class="header-anchor" href="#容器-vs-lambda-vs-ec2-什麼時候選容器" aria-label="Permalink to &quot;容器 vs Lambda vs EC2：什麼時候選容器&quot;">​</a></h2><p>容器不是唯一的運算選擇，它夾在 EC2 與 Lambda 之間：</p><ul><li>要<strong>完全掌控作業系統、跑常駐或特殊工作</strong> → <strong>EC2</strong></li><li>要<strong>短小、事件觸發、閒置不付錢</strong> → <strong>Lambda</strong></li><li>要<strong>把應用打包成到處都能一致執行的單位、做微服務、或搬移既有的 Docker 應用上雲</strong> → <strong>容器（ECS / EKS）</strong></li></ul><h2 id="重點整理" tabindex="-1">重點整理 <a class="header-anchor" href="#重點整理" aria-label="Permalink to &quot;重點整理&quot;">​</a></h2><ul><li><strong>容器 vs 虛擬機</strong>：容器只打包「應用 + 相依套件」、<strong>共用主機 OS 核心</strong>，所以輕量、秒啟、好搬移；VM（如 EC2）各帶一份完整 OS，較重但隔離更強。兩者常搭配使用（容器跑在 VM 裡）。</li><li><strong>映像檔 vs 容器</strong>：映像檔是唯讀範本，容器是由映像檔啟動的執行實體；一個映像檔可啟動多個容器。</li><li><strong>編排（Orchestration）</strong> = 自動調度大量容器（排程、重啟、擴縮）。</li><li><strong>兩個要分開的決定</strong>：①用哪個編排器 <strong>ECS（AWS 原生、簡單、控制平面免費）vs EKS（開源 K8s、可跨雲、較複雜）</strong>；②容器跑在哪 <strong>EC2 啟動類型（自管主機、最多掌控）vs Fargate（免管主機、最省事）</strong>。</li><li><strong>ECR</strong> = 私有映像檔倉庫，ECS / EKS 從這裡拉映像，支援版本管理與弱點掃描。</li></ul><table tabindex="0"><thead><tr><th>情境需求</th><th>答案</th></tr></thead><tbody><tr><td>要 AWS 原生、最簡單的容器編排</td><td><strong>ECS</strong></td></tr><tr><td>要開源 Kubernetes、可跨雲 / 地端移植</td><td><strong>EKS</strong></td></tr><tr><td>跑容器但完全不想管底層主機</td><td><strong>Fargate</strong></td></tr><tr><td>跑容器且要自管 EC2 主機、要最多掌控</td><td><strong>EC2 啟動類型</strong></td></tr><tr><td>存放與版本管理容器映像檔</td><td><strong>ECR</strong></td></tr><tr><td>掃描映像檔裡的已知漏洞</td><td><strong>ECR（映像檔掃描）</strong></td></tr><tr><td>把既有 Docker 應用一致地搬上雲</td><td><strong>容器（ECS / EKS）</strong></td></tr><tr><td>短小、事件觸發的工作</td><td><strong>Lambda</strong></td></tr></tbody></table>`,42)])])}const b=r(e,[["render",o]]);export{h as __pageData,b as default};
